bool is_whitespace_char(char c)
{
    if (c == ' ') return true;
    if (c == '\n') return true;
    if (c == '\r') return true;
    if (c == '\f') return true;
    if (c == '\v') return true;
    if (c == 5) return true;
    else return false;
}

std::optional<int> is_gap(const yy::parser::location_type& loc, driver& drv, std::string_view text, int start)
{
    int length = text.size();
    assert(start<length);

    if (not (start+1 < length and text[start] == '\\' and is_whitespace_char(text[start+1])))
        return {};

    int i = start+2;

    while(i<length and is_whitespace_char(text[i]))
        i++;

    if (i< length and text[i] == '\\')
    {
        i++; // skip the ending backslash also
    }
    else
    {
        yy::parser::location_type loc2(loc.begin+start, loc.begin+i);
        drv.push_error_message(loc2, Note()<<"invalid string: whitespace gap is missing final '\\'");
    }
    return i;
}

struct ParsedChar
{
    std::optional<char32_t> value;
    int next_pos;
};

// Recognize the decimal digits allowed in numeric character escapes.
static bool is_ascii_digit(char c)
{
    return '0' <= c and c <= '9';
}

// Parse one decimal numeric escape after a backslash, preserving the source
// span for diagnostics and detecting overflow before it can wrap.
ParsedChar get_decimal_escape(const yy::parser::location_type& loc, driver& drv, std::string_view text, int length, int i)
{
    assert(i+1 < length);
    assert(text[i] == '\\');
    assert(is_ascii_digit(text[i+1]));

    std::uint32_t c = 0;
    bool overflow = false;
    int j = i+1;
    while(j < length and is_ascii_digit(text[j]))
    {
        auto digit = static_cast<std::uint32_t>(text[j] - '0');
        if (c > (0x10FFFF - digit) / 10)
            overflow = true;
        else
            c = 10*c + digit;
        j++;
    }

    if (overflow or not utf8::is_scalar_value(c))
    {
        yy::parser::location_type loc2(loc.begin+i, loc.begin+j);
        drv.push_error_message(loc2, Note()<<"numeric character escape is not a Unicode scalar value");
        c = '?';
    }

    return {static_cast<char32_t>(c), j};
}

// Parse one character or escape from a character/string literal.  A missing
// value represents Haskell's empty string-only escape `\&`.
ParsedChar get_char(const yy::parser::location_type& loc, driver& drv, std::string_view text, int length, int i)
{
    assert(i < length);

    char32_t c = static_cast<unsigned char>(text[i]);
    if (c == '\\')
    {
        if (i+1 >= length)
        {
            assert(text.size() > 2 and text[text.size()-2] == '\\');
            yy::parser::location_type loc2(loc.begin+i, loc.begin+i+2);
            drv.push_error_message(loc2, Note()<<"invalid escape of ending quote");
            return {'?',i+2};
        }

	c = static_cast<unsigned char>(text[i+1]);
        if (is_ascii_digit(static_cast<char>(c)))
            return get_decimal_escape(loc, drv, text, length, i);
	else if (c == 'a')
	    c = '\a';
	else if (c == 'b')
	    c = '\b';
	else if (c == 'f')
	    c = '\f';
	else if (c == 'n')
	    c = '\n';
	else if (c == 'r')
	    c = '\r';
	else if (c == 't')
	    c = '\t';
	else if (c == 'v')
	    c = '\v';
	else if (c == '"')
	    c = '"';
	else if (c == '\'')
	    c = '\'';
	else if (c == '\\')
	    c = '\\';
        else if (c == '&')
            return {std::nullopt, i+2};
	else
        {
            yy::parser::location_type loc2(loc.begin+i);
            loc2 += 2;
            auto msg = Note()<<"invalid escape sequence '\\"<<static_cast<char>(c)<<"'";
            drv.push_error_message(loc2, msg);

            c = '?';
        }
        return {c,i+2};

    }
    auto decoded = utf8::decode_next(text, i);
    if (not decoded or decoded->next_byte > static_cast<std::size_t>(length))
    {
        yy::parser::location_type loc2(loc.begin+i);
        loc2 += 1;
        drv.push_error_message(loc2, Note()<<"invalid UTF-8 character in literal");
        return {'?', i+1};
    }
    return {decoded->code_point, static_cast<int>(decoded->next_byte)};
}

yy::parser::symbol_type make_char(std::string_view text, const yy::parser::location_type& loc, driver& drv)
{
    int i=1;
    auto [c,_] = get_char(loc, drv, text, text.size() - 1, i);
    if (not c)
    {
        yy::parser::location_type loc2(loc.begin+i, loc.begin+i+2);
        drv.push_error_message(loc2, Note()<<"empty escape '\\&' is not valid in a character literal");
        c = '?';
    }

    return yy::parser::make_CHAR(*c,loc);
}

yy::parser::symbol_type make_string(std::string_view text, const yy::parser::location_type& loc, driver& drv)
{
//    std::cerr<<"analyzing string: '"<<text<<"'\n";
    std::string s;
    for(int i=1;i<text.size()-1;)
    {
//        std::cerr<<"   looking at: '"<<text.substr(i)<<"'\n";
        if (auto after_gap = is_gap(loc, drv, text.substr(0, text.size()-1), i))
            i = *after_gap;
        else
        {
            auto [c, next_pos] = get_char(loc, drv, text, text.size()-1, i);
            if (c)
                s += utf8::encode(*c);
            i = next_pos;
        }
    }

//    std::cerr<<"got string: '"<<s<<"'\n";

    return yy::parser::make_STRING(s,loc);
}

